CREATE VIEW "public"."current_published_documents" AS (with "sq" as (select "id", "document_id", "collection_id", "path", "event_type", "status", "is_deleted", "created_at", "updated_at", "created_by", "change_summary", row_number() OVER (PARTITION BY "document_id" ORDER BY "id" DESC) as "rn" from "document_versions" where "document_versions"."is_deleted" = false AND "document_versions"."status" = 'published') select "id", "document_id", "collection_id", "path", "event_type", "status", "is_deleted", "created_at", "updated_at", "created_by", "change_summary" from "sq" where "rn" = 1);